SELECT c.*, gif.gift_nm AS gift_nm, ste.site_nm AS site_nm, cd_gct.code_label AS cond_type_cd_nm FROM pm_gift_cond c LEFT JOIN pm_gift gif ON gif.gift_id = c.gift_id LEFT JOIN sy_site ste ON ste.site_id = c.site_id LEFT JOIN sy_code cd_gct ON cd_gct.code_grp = 'GIFT_COND_TYPE' AND cd_gct.code_value = c.cond_type_cd
ORDER BY c.gift_cond_id ASC ORDER BY c.gift_cond_id DESC ORDER BY c.reg_date ASC ORDER BY c.reg_date DESC ORDER BY c.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

SELECT c.*, gif.gift_nm AS gift_nm, ste.site_nm AS site_nm, cd_gct.code_label AS cond_type_cd_nm FROM pm_gift_cond c LEFT JOIN pm_gift gif ON gif.gift_id = c.gift_id LEFT JOIN sy_site ste ON ste.site_id = c.site_id LEFT JOIN sy_code cd_gct ON cd_gct.code_grp = 'GIFT_COND_TYPE' AND cd_gct.code_value = c.cond_type_cd
ORDER BY c.gift_cond_id ASC ORDER BY c.gift_cond_id DESC ORDER BY c.reg_date ASC ORDER BY c.reg_date DESC ORDER BY c.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

