gift_id = #{giftId}, site_id = #{siteId}, cond_type_cd = #{condTypeCd}, min_order_amt = #{minOrderAmt}, target_type_cd = #{targetTypeCd}, target_id = #{targetId},
WHERE gift_cond_id = #{giftCondId}
